)

{
 //number of cable connections
 int edges = cableConnections.size();

 //number of reconnections required
 int reconnections = 0;

 //minimum number of cable connections required to connect given number of computers- computerCount
 if (edges < computerCount - 1){
  return -1;
 }

 //to check all computers that are connected
 vector<bool> visited(computerCount, false);

 //to track direct connections
 vector<vector<int>> list (cableConnections);

 for(int cables = 0; cables < edges; cables++){
  list[cableConnections[cables][0]].push_back(cableConnections[cables][1]);
 }

 //initialize the first node and insert it into a queue
 int start = 0;
 queue<int> q;
 q.push(start);

 visited[start] = true;

 //count - to keep a track of nodes traversed
 int count = 0;

 //bfs approach to check for all connected nodes from node zero
 while(!q.empty()){
  //pop the front node of the queue
  int node = q.front();
  q.pop();

  //check and add all directly connected nodes to the front node, into the queue
  for(int x : list[node]){
   count++;
   if(!visited[x]){
    q.push(x);
    visited[x] = true;
   }
  }
 }

 //count number of nodes connected to zero
 int conZero = 0;
 for(int i=1; i < computerCount; i++){
  if(visited[i]){
   conZero = true;
  }
 }

 //number of disconnected components
 int disConnected = 0;

 //for all disconnected nodes from '0'
 for(int i = 1; i < computerCount; i++){
  if(!visited[i]){
   disConnected++;
   visited[i] = true;

   //apply bfs to disconnected node to check all other nodes connected to it
   q.push(i);
   while(!q.empty()){

   }
  }
 }

 int spare = count - conZero;

 if(spare > disConnected){
  reconnections = disConnected;
 }else{
  reconnections = -1;
 }

 return reconnections;
}

