class Solution {
public:
 vector<int> findCourseOrder(int totalCourses, vector<vector<int>>& coursePrerequisites) {
  queue<int>q;
  vector<bool>visited(totalCourses, false);
  vector<int>indegree(totalCourses,0);
  vector<int>sequence;

  // write your code here
  int n = coursePrerequisites.size();
  for(int i=0; i<n; i++){
   indegree[coursePrerequisites[i][1]]++;
  }

  for(int i=0; i<totalCourses; i++){
   if(indegree[i]==0){
    q.push(i);
   }
  }

  while(!q.empty()){
   int node = q.front();
   q.pop();
   sequence.push_back(node);
   visited[node] = true;
   for(int i=0; i<totalCourses; i++){
    for(int j=0; j<n; j++){
     if(!visited[i] && coursePrerequisites[j][1]==i){
      indegree[i]--;
      if(indegree[i]==0){
       q.push(i);
      }
     }
    }
   }
  }
  return sequence;
 }

};

