#include <bits/stdc++.h>
using namespace std;
vector<vector<int>> ans;
vector<int> num;
vector<int> curr;
unordered_set<int> used;
void generatepermutation(int i,int n){

 if(i == n)
 {
  ans.push_back(curr);
  return;
 }
 for(int idx = 0 ; idx < n ; idx++)
 {
  if(used.find(num[idx]) == used.end())
  {
   curr.push_back(num[idx]);
   used.insert(num[idx]);
   generatepermutation(i+1,n);
   used.erase(num[idx]);
   curr.pop_back();
  }
 }
}
int main() {
 int t;
 cin >> t;
 while(t--)
 {
 ans.clear();
 num.clear();
 curr.clear();
 used.clear();
 int n,m;
 cin >> n >> m;
  long long rope = -1;
  for(int i = 1 ; i <= n ; i++){
   num.push_back(i);
  }
  generatepermutation(0,n);
  for(auto &it : ans)
  {
   long long dist = 0;
   vector<int> pos(n+2,-1);
   pos[0] = 0;
   pos[n+1] = n+1;
   for(auto &node : it)
   {
    int left = 0;
    int right = n+1;
    for(int i = 0 ; i < node ; i++)
    {
     if(pos[i] == -1) continue;
     left = max(left,pos[i]);
    }
    for(int i = node ; i < n+2 ; i++)
    {
     if(pos[i] == -1) continue;
     right = min(right,pos[i]);
    }
    pos[node] = node;
    dist += ((node - left) + (right - node));
   }
   if(dist <= m)
   {
    rope = max(rope,dist);
   }
  }
  if(rope == -1)
  {
   cout << -1;
   cout << endl;
   continue;
  }
  cout << m - rope;
  cout << endl;
 }
}

